1	<?php
2	/**
3	 * Cloudflare Tunnel URL Rewrite — Path-based Multisite Routing
4	 *
5	 * Funciona em conjunto com sunrise.php que faz o domain mapping real.
6	 * Reescreve URLs no output substituindo cambrasmax.local:<porta> pelo tunnel hostname,
7	 * preservando os paths dos subsites (/cultura/).
8	 *
9	 * Single tunnel serve todos os subsites:
10	 *   - concertacao.bureau-it.com/         → blog_id=1 (site raiz)
11	 *   - concertacao.bureau-it.com/cultura/ → blog_id=2
12	 *
13	 * Customizado para subsite domain mapping - EDITAR COM CUIDADO
14	 */
15	
16	// Belt-and-suspenders: este mu-plugin é DEV-ONLY. Em prod (mesmo se sunrise.php
17	// for sincronizado por engano com mapping de tunnel), aborta antes de qualquer ob_start.
18	if (function_exists('wp_get_environment_type') && wp_get_environment_type() !== 'development') {
19	    return;
20	}
21	
22	// TUNNEL_ORIGINAL_HOST é definido pelo sunrise.php (antes do multisite init)
23	if (!defined('TUNNEL_ORIGINAL_HOST')) {
24	    return;
25	}
26	
27	// Configuração por tunnel hostname
28	$tunnel_configs = [
29	    'concertacao.bureau-it.com' => [
30	        'public_url'   => 'https://concertacao.bureau-it.com',
31	        'subsite_path' => '',   // site raiz — sem strip de path
32	    ],
33	];
34	
35	if (!isset($tunnel_configs[TUNNEL_ORIGINAL_HOST])) {
36	    return;
37	}
38	
39	$config = $tunnel_configs[TUNNEL_ORIGINAL_HOST];
40	
41	// Porta local lida dinamicamente do siteurl atual — evita drift quando NGINX_SSL_PORT muda no .env
42	$_siteurl_port = parse_url(get_option('siteurl'), PHP_URL_PORT);
43	$_local_port   = $_siteurl_port ? ':' . (int) $_siteurl_port : '';
44	
45	define('TUNNEL_LOCAL_URL',    'https://cambrasmax.local' . $_local_port);
46	define('TUNNEL_LOCAL_ALT',    'https://localhost' . $_local_port);
47	define('TUNNEL_LOCAL_NOPORT', 'https://cambrasmax.local');
48	define('TUNNEL_PUBLIC_URL',   $config['public_url']);
49	define('TUNNEL_SUBSITE_PATH', $config['subsite_path']);
50	
51	// URLs a substituir — ORDEM IMPORTA: subsite com prefixo primeiro, depois base
52	$tunnel_search  = [];
53	$tunnel_replace = [];
54	
55	if (TUNNEL_SUBSITE_PATH !== '') {
56	    // Subsite URLs (com prefixo) → tunnel root (strip prefix)
57	    foreach ([TUNNEL_LOCAL_URL, TUNNEL_LOCAL_ALT, TUNNEL_LOCAL_NOPORT] as $local) {
58	        $tunnel_search[]  = $local . TUNNEL_SUBSITE_PATH;
59	        $tunnel_search[]  = str_replace('/', '\\/', $local . TUNNEL_SUBSITE_PATH);
60	        $tunnel_replace[] = TUNNEL_PUBLIC_URL;
61	        $tunnel_replace[] = str_replace('/', '\\/', TUNNEL_PUBLIC_URL);
62	    }
63	}
64	
65	// Base URLs (shared resources: wp-content, wp-includes) → tunnel root
66	foreach ([TUNNEL_LOCAL_URL, TUNNEL_LOCAL_ALT, TUNNEL_LOCAL_NOPORT] as $local) {
67	    $tunnel_search[]  = $local;
68	    $tunnel_search[]  = str_replace('/', '\\/', $local);
69	    $tunnel_replace[] = TUNNEL_PUBLIC_URL;
70	    $tunnel_replace[] = str_replace('/', '\\/', TUNNEL_PUBLIC_URL);
71	}
72	
73	// Global output buffer - captura TODO output PHP (HTML, JSON, AJAX, REST)
74	ob_start(function ($html) use ($tunnel_search, $tunnel_replace) {
75	    return str_replace($tunnel_search, $tunnel_replace, $html);
76	});
77	
78	function tunnel_rewrite_url($url) {
79	    if (TUNNEL_SUBSITE_PATH !== '') {
80	        $url = str_replace(
81	            [
82	                TUNNEL_LOCAL_URL . TUNNEL_SUBSITE_PATH,
83	                TUNNEL_LOCAL_ALT . TUNNEL_SUBSITE_PATH,
84	                TUNNEL_LOCAL_NOPORT . TUNNEL_SUBSITE_PATH,
85	            ],
86	            [TUNNEL_PUBLIC_URL, TUNNEL_PUBLIC_URL, TUNNEL_PUBLIC_URL],
87	            $url
88	        );
89	    }
90	    return str_replace(
91	        [TUNNEL_LOCAL_URL, TUNNEL_LOCAL_ALT, TUNNEL_LOCAL_NOPORT],
92	        [TUNNEL_PUBLIC_URL, TUNNEL_PUBLIC_URL, TUNNEL_PUBLIC_URL],
93	        $url
94	    );
95	}
96	
97	// Option-level (interceptação mais cedo possível)
98	add_filter('option_home',    'tunnel_rewrite_url');
99	add_filter('option_siteurl', 'tunnel_rewrite_url');
100	
101	// URL generation functions
102	add_filter('home_url',     'tunnel_rewrite_url');
103	add_filter('site_url',     'tunnel_rewrite_url');
104	add_filter('admin_url',    'tunnel_rewrite_url');
105	add_filter('includes_url', 'tunnel_rewrite_url');
106	add_filter('content_url',  'tunnel_rewrite_url');
107	add_filter('plugins_url',  'tunnel_rewrite_url');
108	add_filter('rest_url',     'tunnel_rewrite_url');
109	
110	// Asset loader sources
111	add_filter('script_loader_src', 'tunnel_rewrite_url');
112	add_filter('style_loader_src',  'tunnel_rewrite_url');
113	
114	// Media e attachments
115	add_filter('wp_get_attachment_url', 'tunnel_rewrite_url');
116	
117	// Theme URIs
118	add_filter('template_directory_uri',   'tunnel_rewrite_url');
119	add_filter('stylesheet_directory_uri', 'tunnel_rewrite_url');
120	add_filter('theme_root_uri',           'tunnel_rewrite_url');
121	
122	// Upload directory (recebe array, não string)
123	add_filter('upload_dir', function ($uploads) {
124	    $uploads['url']     = tunnel_rewrite_url($uploads['url']);
125	    $uploads['baseurl'] = tunnel_rewrite_url($uploads['baseurl']);
126	    return $uploads;
127	});
128	
129	// Desabilitar redirect_canonical para tunnel (evita loop por divergência de port)
130	add_filter('redirect_canonical', '__return_false');
131	
132	// Redirect URLs (header Location: não é capturado pelo ob_start)
133	add_filter('wp_redirect', 'tunnel_rewrite_url');
134	
135	// dns-prefetch / preconnect hints: wp_resource_hints() emite hints em formatos variados
136	// — string "cambrasmax.local" (host puro, gerado por wp_dependencies_unique_hosts),
137	// "//cambrasmax.local" (sem scheme), "https://cambrasmax.local:8484" (com scheme/porta),
138	// ou array ['href' => ..., 'crossorigin' => ...]. Nenhum casa o str_replace do ob_start.
139	//
140	// Prioridade PHP_INT_MAX-10: garantir execução APÓS WP Rocket / Site Kit / S3-Uploads
141	// (todos prio 10) que podem injetar hints próprios apontando para o host local.
142	add_filter('wp_resource_hints', function ($hints, $relation_type) {
143	    $tunnel_host = parse_url(TUNNEL_PUBLIC_URL, PHP_URL_HOST);
144	    foreach ($hints as $i => $hint) {
145	        $url = is_array($hint) ? ($hint['href'] ?? '') : $hint;
146	        if (stripos($url, 'cambrasmax.local') === false && stripos($url, 'localhost') === false) continue;
147	        // Anchors `^` + lookahead `(?=/|$)`: só casa quando o segmento é exatamente
148	        // o host (eventualmente com scheme + porta), não substring de outro hostname
149	        // como `sub.cambrasmax.local` ou `cambrasmax.local.example.com`.
150	        $new_url = preg_replace(
151	            '#^((?:https?:)?//)?(?:cambrasmax\.local|localhost)(?::\d+)?(?=/|$)#i',
152	            '$1' . $tunnel_host,
153	            $url
154	        );
155	        if (is_array($hint)) { $hint['href'] = $new_url; $hints[$i] = $hint; }
156	        else                 { $hints[$i]    = $new_url; }
157	    }
158	    return $hints;
159	}, PHP_INT_MAX - 10, 2);
160

1	<?php
2	/**
3	 * Plugin Name: BIT Multisite Menu URL
4	 * Description: Corrige URLs de menu cross-blog em multisite subdirectory com WPML.
5	 *              Garante que itens do Blog 1 apontando para o Blog 2 usem o padrão
6	 *              correto de idioma: /{subsite}/{lang}/ em vez de /{lang}/{subsite}/.
7	 * Version: 1.0.0
8	 * Author: Bureau de Tecnologia
9	 */
10	
11	if ( ! defined( 'ABSPATH' ) ) {
12		exit;
13	}
14	
15	/**
16	 * Mapeamento de subsites: path do subsite => idiomas suportados (exceto o default).
17	 * Adicionar novos subsites aqui conforme o multisite crescer.
18	 *
19	 * @filter bit_multisite_subsite_langs
20	 */
21	$bit_multisite_subsite_langs = apply_filters( 'bit_multisite_subsite_langs', [
22		'cultura' => [ 'en' ],
23	] );
24	
25	/**
26	 * Reescreve URLs de itens de menu custom que usam o padrão errado /{lang}/{subsite}/
27	 * para o padrão correto /{subsite}/{lang}/ antes do render.
28	 *
29	 * Executa em priority 5, antes do filtro WPML (priority 10 em wp_nav_menu_args),
30	 * o que garante que o WPML não interfere com a correção.
31	 */
32	add_filter( 'wp_nav_menu_objects', function ( array $items ) use ( $bit_multisite_subsite_langs ): array {
33		foreach ( $items as $item ) {
34			if ( empty( $item->url ) || $item->type !== 'custom' ) {
35				continue;
36			}
37	
38			$url = $item->url;
39	
40			foreach ( $bit_multisite_subsite_langs as $subsite => $langs ) {
41				foreach ( $langs as $lang ) {
42					// Detectar padrão errado: /{lang}/{subsite}/ → /{subsite}/{lang}/
43					// Ex: /en/cultura/ → /cultura/en/
44					// Funciona para qualquer hostname (local, tunnel, prod).
45					$wrong_pattern  = "/{$lang}/{$subsite}/";
46					$correct_prefix = "/{$subsite}/{$lang}/";
47	
48					if ( strpos( $url, $wrong_pattern ) !== false ) {
49						$item->url = str_replace( $wrong_pattern, $correct_prefix, $url );
50						break 2;
51					}
52				}
53			}
54		}
55	
56		return $items;
57	}, 5 ); // Priority 5: antes do WPML (priority 10)
